import React, { useState } from "react";
import { Link, useNavigate } from "react-router-dom";
import { useAuth } from "../contexts/AuthContext";
import Navbar from "../components/Navbar";
import { toast } from "sonner";

export default function Register() {
  const { register } = useAuth();
  const nav = useNavigate();
  const [name, setName] = useState("");
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [busy, setBusy] = useState(false);

  const submit = async (e) => {
    e.preventDefault();
    setBusy(true);
    try {
      await register(email, password, name);
      toast.success("welcome to spectral forge");
      nav("/dashboard");
    } catch (err) {
      toast.error(err?.response?.data?.detail || "registration failed");
    } finally {
      setBusy(false);
    }
  };

  return (
    <div className="min-h-screen bg-black text-white">
      <Navbar floating={false} />
      <div className="max-w-md mx-auto px-6 pt-24 pb-16">
        <h1 className="hero-title text-5xl font-medium mb-2" data-testid="register-title">join the forge</h1>
        <p className="text-white/60 mb-8 text-sm">create your members account to submit projects.</p>

        <form onSubmit={submit} className="space-y-3">
          <input
            value={name}
            onChange={(e) => setName(e.target.value)}
            placeholder="display name"
            data-testid="register-name-input"
            className="w-full bg-neutral-900/90 border border-white/10 rounded-full px-5 py-3 text-sm text-white placeholder-white/40 focus:outline-none focus:border-white/30"
          />
          <input
            type="email"
            required
            value={email}
            onChange={(e) => setEmail(e.target.value)}
            placeholder="email"
            data-testid="register-email-input"
            className="w-full bg-neutral-900/90 border border-white/10 rounded-full px-5 py-3 text-sm text-white placeholder-white/40 focus:outline-none focus:border-white/30"
          />
          <input
            type="password"
            required
            minLength={6}
            value={password}
            onChange={(e) => setPassword(e.target.value)}
            placeholder="password (min 6)"
            data-testid="register-password-input"
            className="w-full bg-neutral-900/90 border border-white/10 rounded-full px-5 py-3 text-sm text-white placeholder-white/40 focus:outline-none focus:border-white/30"
          />
          <button
            type="submit"
            disabled={busy}
            data-testid="register-submit-btn"
            className="w-full bg-white text-black rounded-full py-3 text-sm font-normal hover:bg-neutral-200 transition-colors disabled:opacity-50"
          >
            {busy ? "creating..." : "create account"}
          </button>
        </form>

        <div className="mt-6 text-sm text-white/60">
          already have an account? <Link to="/login" data-testid="register-login-link" className="hover:text-white transition-colors">sign in</Link>
        </div>
      </div>
    </div>
  );
}
